def mode_count(nums):
    if not nums:
        return 0
    counter = {}
    max_freq, mode_count = 0, 0
    for num in nums:
        if num not in counter:
            counter[num] = 1
        else:
            counter[num] += 1
        max_freq = max(max_freq, counter[num])

    for freq in counter.values():
        if freq == max_freq:
            mode_count += 1

    return mode_count
